import './GridItem.scss';

import { Box } from ':components/Box';
import { classNames } from ':helpers/classnames';
import type { FC } from 'react';
import React from 'react';
import type { GridItemProps } from './GridItem.types';

export const GridItem: FC<GridItemProps> = ({
	colSpan,
	rowSpan,
	colStart,
	rowStart,
	align,
	justify,
	className,
	dataTestId = 'GridItem',
	...rest
}) => {
	const gridItemClassName = classNames(
		'dsb_grid-item',
		colSpan && `dsb_grid-item__col-span-${colSpan}`,
		rowSpan && `dsb_grid-item__row-span-${rowSpan}`,
		colStart && `dsb_grid-item__col-start-${colStart}`,
		rowStart && `dsb_grid-item__row-start-${rowStart}`,
		align && `dsb_grid-item__align-${align}`,
		justify && `dsb_grid-item__justify-${justify}`,
		className,
	);

	return <Box className={gridItemClassName} dataTestId={dataTestId} {...rest} />;
};

GridItem.displayName = 'GridItem';
